/**
 * Tasks Quick Add Widget
 *
 * Simple widget for quickly adding tasks to the Kanban board
 * Focused, single-purpose interface
 */

import React, { useState } from 'react';
import { BaseWidget } from './BaseWidget';
import { useKanbanStore } from '../../stores/useKanbanStore';

export const TasksQuickAddWidget: React.FC = () => {
  const { addTask } = useKanbanStore();
  const [input, setInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      addTask({
        title: input.trim(),
        description: '',
        status: 'todo',
        priority: 'medium',
        tags: [],
        startDate: null,
        dueDate: null,
      });
      setInput('');
    }
  };

  return (
    <BaseWidget title="Quick Add Task" icon="➕">
      <div className="flex flex-col h-full min-h-[160px]">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => { if (e.key === 'Enter' && input.trim()) handleSubmit(e); }}
          placeholder="Add a task..."
          className="w-full px-4 py-2.5 border rounded-button transition-all duration-standard ease-smooth
                     bg-white dark:bg-surface-dark
                     text-text-light-primary dark:text-text-dark-primary
                     border-border-light dark:border-border-dark
                     focus:outline-none focus:ring-2 focus:ring-accent-blue mb-4"
          autoFocus
        />
        <button
          type="button"
          onClick={handleSubmit}
          disabled={!input.trim()}
          className="w-full mt-auto px-4 py-2.5 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 disabled:cursor-not-allowed text-white rounded-button transition-all duration-standard ease-smooth text-sm font-medium"
        >
          Add Task
        </button>
      </div>
    </BaseWidget>
  );
};

/**
 * Upcoming Events Widget
 *
 * Shows next 3 upcoming calendar events
 */

import React from 'react';
import { BaseWidget } from './BaseWidget';
import { useCalendarStore } from '../../stores/useCalendarStore';
import { useNavigate } from 'react-router-dom';

export const UpcomingEventsWidget: React.FC = () => {
  const { events } = useCalendarStore();
  const navigate = useNavigate();

  const upcomingEvents = Object.entries(events)
    .flatMap(([dateKey, eventList]) =>
      eventList.map((event) => ({ ...event, date: dateKey }))
    )
    .filter((event) => new Date(event.date) >= new Date())
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
    .slice(0, 3);

  return (
    <BaseWidget title="Upcoming Events" icon="📅">
      <div className="flex flex-col h-full min-h-[160px]">
        {upcomingEvents.length > 0 ? (
          <div className="space-y-2 mb-4">
            {upcomingEvents.map((event) => (
              <div key={event.id} className="flex items-start gap-3 p-2 rounded hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth">
                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary w-20 flex-shrink-0">
                  {new Date(event.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-medium text-text-light-primary dark:text-text-dark-primary">{event.title}</div>
                  {event.startTime && (
                    <div className="text-sm text-accent-blue dark:text-accent-blue-hover">{event.startTime}</div>
                  )}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">No upcoming events</p>
        )}
        <button
          onClick={() => navigate('/schedule')}
          className="w-full mt-auto px-4 py-2.5 bg-accent-magenta hover:bg-accent-magenta-hover text-white rounded-button text-sm font-medium transition-all duration-standard ease-smooth"
        >
          View Calendar →
        </button>
      </div>
    </BaseWidget>
  );
};

