     1→import { create } from 'zustand';
     2→import { persist, createJSONStorage } from 'zustand/middleware';
     3→import type { CalendarState, ViewMode, CalendarEvent } from '../types';
     4→import { createSyncedStorage } from '../lib/syncedStorage';
     5→import { getStandardDateKey } from '../utils/dateUtils';
     6→import { scheduleEventReminders, cancelEventReminders } from '../services/eventReminders';
     7→import { logger } from '../services/logger';
     8→
     9→const log = logger.module('CalendarStore');
    10→
    11→/**
    12→ * One-time migration: Convert legacy date keys (0-indexed month) to standard keys (1-indexed month)
    13→ * Legacy format: "2025-0-15" (January 15)
    14→ * Standard format: "2025-1-15" (January 15)
    15→ */
    16→function migrateLegacyDateKeys(events: Record<string, CalendarEvent[]>): Record<string, CalendarEvent[]> {
    17→  const migratedEvents: Record<string, CalendarEvent[]> = {};
    18→  let migrationCount = 0;
    19→
    20→  for (const [oldKey, eventList] of Object.entries(events)) {
    21→    // Parse old key format: "YYYY-M-D"
    22→    const parts = oldKey.split('-');
    23→    if (parts.length === 3) {
    24→      const year = parseInt(parts[0], 10);
    25→      const month = parseInt(parts[1], 10);  // Could be 0-indexed (legacy) or 1-indexed (already migrated)
    26→      const day = parseInt(parts[2], 10);
    27→
    28→      // Detect if this is a legacy key (month 0-11) by checking if it's likely 0-indexed
    29→      // Legacy keys had month 0-11, so month values 0-11 are suspicious for dates past January
    30→      const isLikelyLegacyKey = month >= 0 && month <= 11;
    31→
    32→      if (isLikelyLegacyKey) {
    33→        // Create date assuming 0-indexed month, then convert to standard key
    34→        const date = new Date(year, month, day);
    35→        const newKey = getStandardDateKey(date);  // This will use month + 1
    36→
    37→        if (oldKey !== newKey) {
    38→          migratedEvents[newKey] = eventList;
    39→          migrationCount++;
    40→        } else {
    41→          // Key didn't change (e.g., was already in correct format)
    42→          migratedEvents[oldKey] = eventList;
    43→        }
    44→      } else {
    45→        // Month > 11, likely already migrated or malformed - keep as-is
    46→        migratedEvents[oldKey] = eventList;
    47→      }
    48→    } else {
    49→      // Non-standard key format - keep as-is
    50→      migratedEvents[oldKey] = eventList;
    51→    }
    52→  }
    53→
    54→  if (migrationCount > 0) {
    55→    log.info('Migrated calendar event keys to standard format', { count: migrationCount });
    56→  }
    57→
    58→  return migratedEvents;
    59→}
    60→
    61→interface CalendarStore extends CalendarState {
    62→  setViewMode: (mode: ViewMode) => void;
    63→  setCurrentDate: (date: Date) => void;
    64→  addEvent: (dateKey: string, title: string, description?: string, timeData?: Partial<CalendarEvent>) => void;
    65→  updateEvent: (dateKey: string, eventId: string, title: string, description?: string, timeData?: Partial<CalendarEvent>) => void;
    66→  deleteEvent: (dateKey: string, eventId: string) => void;
    67→  removeAllEvents: (dateKey: string) => void;
    68→  createEventException: (dateKey: string, recurrenceId: string, updates: Partial<CalendarEvent>) => void;
    69→  updateRecurringSeries: (recurrenceId: string, updates: Partial<CalendarEvent>) => void;
    70→  deleteRecurringSeries: (recurrenceId: string) => void;
    71→  nextPeriod: () => void;
    72→  prevPeriod: () => void;
    73→  // ICS Import/Export
    74→  importEvents: (events: (CalendarEvent & { _importedDate?: string })[]) => number;
    75→}
    76→
    77→export const useCalendarStore = create<CalendarStore>()(
    78→  persist(
    79→    (set) => ({
    80→      // Initial state
    81→      events: {},
    82→      viewMode: 'monthly',
    83→      currentDate: new Date(),
    84→
    85→      // Actions
    86→      setViewMode: (mode) => set({ viewMode: mode }),
    87→
    88→      setCurrentDate: (date) => set({ currentDate: date }),
    89→
    90→      addEvent: (dateKey, title, description, timeData) =>
    91→        set((state) => {
    92→          const newEvent: CalendarEvent = {
    93→            id: Date.now().toString(),
    94→            title,
    95→            description,
    96→            ...timeData,
    97→          };
    98→          const existingEvents = state.events[dateKey] || [];
    99→
   100→          // Schedule reminders for the new event
   101→          scheduleEventReminders(newEvent, dateKey);
   102→
   103→          return {
   104→            events: {
   105→              ...state.events,
   106→              [dateKey]: [...existingEvents, newEvent],
   107→            },
   108→          };
   109→        }),
   110→
   111→      updateEvent: (dateKey, eventId, title, description, timeData) =>
   112→        set((state) => {
   113→          const events = state.events[dateKey] || [];
   114→
   115→          // Cancel existing reminders for this event
   116→          cancelEventReminders(eventId);
   117→
   118→          // Update event and reschedule reminders
   119→          const updatedEvents = events.map((event) => {
   120→            if (event.id === eventId) {
   121→              const updatedEvent = { ...event, title, description, ...timeData };
   122→              // Reschedule reminders with new data
   123→              scheduleEventReminders(updatedEvent, dateKey);
   124→              return updatedEvent;
   125→            }
   126→            return event;
   127→          });
   128→
   129→          return {
   130→            events: {
   131→              ...state.events,
   132→              [dateKey]: updatedEvents,
   133→            },
   134→          };
   135→        }),
   136→
   137→      deleteEvent: (dateKey, eventId) =>
   138→        set((state) => {
   139→          const events = state.events[dateKey] || [];
   140→
   141→          // Cancel reminders for the deleted event
   142→          cancelEventReminders(eventId);
   143→
   144→          const filteredEvents = events.filter((event) => event.id !== eventId);
   145→
   146→          if (filteredEvents.length === 0) {
   147→            // Remove the date key if no events left
   148→            const newEvents = { ...state.events };
   149→            delete newEvents[dateKey];
   150→            return { events: newEvents };
   151→          }
   152→
   153→          return {
   154→            events: {
   155→              ...state.events,
   156→              [dateKey]: filteredEvents,
   157→            },
   158→          };
   159→        }),
   160→
   161→      removeAllEvents: (dateKey) =>
   162→        set((state) => {
   163→          const newEvents = { ...state.events };
   164→          delete newEvents[dateKey];
   165→          return { events: newEvents };
   166→        }),
   167→
   168→      // Create exception for single recurring event instance
   169→      createEventException: (dateKey, recurrenceId, updates) =>
   170→        set((state) => {
   171→          const existingEvents = state.events[dateKey] || [];
   172→          const newEvent: CalendarEvent = {
   173→            id: `${recurrenceId}-exception-${Date.now()}`,
   174→            title: updates.title || 'Untitled',
   175→            recurrenceId,
   176→            recurrenceException: true,
   177→            ...updates,
   178→          };
   179→
   180→          // Schedule reminders for the exception event
   181→          scheduleEventReminders(newEvent, dateKey);
   182→
   183→          return {
   184→            events: {
   185→              ...state.events,
