     2→ * ICS Import/Export Service
     3→ * Handles .ics file parsing and generation for calendar interoperability
     4→ */
     5→
     6→import { createEvents } from 'ics';
     7→import type { CalendarEvent } from '../types';
     8→import { format, parse } from 'date-fns';
     9→
    10→/**
    11→ * Export calendar events to .ics file
    12→ */
    13→export const exportToICS = (events: Record<string, CalendarEvent[]>): { success: boolean; data?: string; error?: string } => {
    14→  try {
    15→    const icsEvents: any[] = [];
    16→
    17→    // Convert all events to ICS format
    18→    Object.entries(events).forEach(([dateKey, dayEvents]) => {
    19→      dayEvents.forEach((event) => {
    20→        // Skip recurring instances (only export parent events)
    21→        if (event.recurrenceId) return;
    22→
    23→        const eventDate = parse(dateKey, 'yyyy-MM-dd', new Date());
    24→        const year = eventDate.getFullYear();
    25→        const month = eventDate.getMonth() + 1; // ICS uses 1-12
    26→        const day = eventDate.getDate();
    27→
    28→        let startTime: [number, number, number, number, number] | undefined;
    29→        let endTime: [number, number, number, number, number] | undefined;
    30→
    31→        // Parse times if timed event
    32→        if (event.startTime && !event.isAllDay) {
    33→          const [startHour, startMinute] = event.startTime.split(':').map(Number);
    34→          startTime = [year, month, day, startHour, startMinute];
    35→
    36→          if (event.endTime) {
    37→            const [endHour, endMinute] = event.endTime.split(':').map(Number);
    38→            endTime = [year, month, day, endHour, endMinute];
    39→          }
    40→        }
    41→
    42→        const icsEvent: any = {
    43→          title: event.title,
    44→          description: event.description,
    45→          start: startTime || [year, month, day],
    46→          startInputType: 'local',
    47→          startOutputType: 'local',
    48→          location: event.location,
    49→          status: 'CONFIRMED',
    50→          busyStatus: 'BUSY',
    51→          uid: event.id,
    52→        };
    53→
    54→        if (endTime) {
    55→          icsEvent.end = endTime;
    56→        }
    57→
    58→        // Add recurrence rule if present
    59→        if (event.recurrence) {
    60→          const { frequency, interval, daysOfWeek, endType, endCount, endDate } = event.recurrence;
    61→
    62→          let rrule = `FREQ=${frequency.toUpperCase()}`;
    63→
    64→          if (interval > 1) {
    65→            rrule += `;INTERVAL=${interval}`;
    66→          }
    67→
    68→          if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
    69→            const days = ['SU', 'MO', 'TU', 'WE', 'TH', 'FR', 'SA'];
    70→            const byDay = daysOfWeek.map((d: number) => days[d]).join(',');
    71→            rrule += `;BYDAY=${byDay}`;
    72→          }
    73→
    74→          if (endType === 'after' && endCount) {
    75→            rrule += `;COUNT=${endCount}`;
    76→          } else if (endType === 'until' && endDate) {
    77→            const untilDate = parse(endDate, 'yyyy-MM-dd', new Date());
    78→            const untilStr = format(untilDate, "yyyyMMdd'T'235959'Z'");
    79→            rrule += `;UNTIL=${untilStr}`;
    80→          }
    81→
    82→          icsEvent.recurrenceRule = rrule;
    83→        }
    84→
    85→        icsEvents.push(icsEvent);
    86→      });
    87→    });
    88→
    89→    const { error, value } = createEvents(icsEvents);
    90→
    91→    if (error) {
    92→      return { success: false, error: error.message };
    93→    }
    94→
    95→    return { success: true, data: value };
    96→  } catch (error) {
    97→    return { success: false, error: String(error) };
    98→  }
    99→};
   100→
   101→/**
   102→ * Parse RRULE string to recurrence object
   103→ */
   104→const parseRRule = (rrule: string): CalendarEvent['recurrence'] | undefined => {
   105→  const parts = rrule.replace('RRULE:', '').split(';');
   106→  const rules: Record<string, string> = {};
   107→
   108→  parts.forEach(part => {
   109→    const [key, value] = part.split('=');
   110→    if (key && value) rules[key] = value;
   111→  });
   112→
   113→  const frequency = rules.FREQ?.toLowerCase() as 'daily' | 'weekly' | 'monthly' | 'yearly';
   114→  if (!frequency) return undefined;
   115→
   116→  const recurrence: CalendarEvent['recurrence'] = {
   117→    frequency,
   118→    interval: rules.INTERVAL ? parseInt(rules.INTERVAL, 10) : 1,
   119→    endType: 'never',
   120→  };
   121→
   122→  // Parse BYDAY for weekly events
   123→  if (rules.BYDAY) {
   124→    const dayMap: Record<string, number> = { SU: 0, MO: 1, TU: 2, WE: 3, TH: 4, FR: 5, SA: 6 };
   125→    recurrence.daysOfWeek = rules.BYDAY.split(',').map(d => dayMap[d]).filter(d => d !== undefined);
   126→  }
   127→
   128→  // Parse COUNT or UNTIL
   129→  if (rules.COUNT) {
   130→    recurrence.endType = 'after';
   131→    recurrence.endCount = parseInt(rules.COUNT, 10);
   132→  } else if (rules.UNTIL) {
   133→    recurrence.endType = 'until';
   134→    // Parse UNTIL format (YYYYMMDDTHHmmssZ or YYYYMMDD)
   135→    const untilStr = rules.UNTIL.replace(/[TZ]/g, '');
   136→    const year = untilStr.slice(0, 4);
   137→    const month = untilStr.slice(4, 6);
   138→    const day = untilStr.slice(6, 8);
   139→    recurrence.endDate = `${year}-${month}-${day}`;
   140→  }
   141→
   142→  return recurrence;
   143→};
   144→
   145→/**
   146→ * Parse ICS date/time string
   147→ */
   148→const parseICSDateTime = (value: string): { date: string; time?: string } => {
   149→  // Handle DTSTART;VALUE=DATE:20231225 or DTSTART:20231225T140000
   150→  const dateStr = value.includes(':') ? value.split(':')[1] : value;
   151→  const cleanDate = dateStr.replace('Z', '');
   152→
   153→  if (cleanDate.length === 8) {
   154→    // Date only: YYYYMMDD
   155→    return {
   156→      date: `${cleanDate.slice(0, 4)}-${cleanDate.slice(4, 6)}-${cleanDate.slice(6, 8)}`,
   157→    };
   158→  } else if (cleanDate.length >= 15) {
   159→    // Date with time: YYYYMMDDTHHmmss
   160→    return {
   161→      date: `${cleanDate.slice(0, 4)}-${cleanDate.slice(4, 6)}-${cleanDate.slice(6, 8)}`,
   162→      time: `${cleanDate.slice(9, 11)}:${cleanDate.slice(11, 13)}`,
   163→    };
   164→  }
   165→
   166→  return { date: cleanDate };
   167→};
   168→
   169→/**
   170→ * Import events from .ics file
   171→ */
   172→export const importFromICS = (icsData: string): { success: boolean; events?: CalendarEvent[]; error?: string } => {
   173→  try {
   174→    // Basic validation
   175→    if (!icsData.includes('BEGIN:VCALENDAR')) {
   176→      return { success: false, error: 'Invalid ICS file format' };
   177→    }
   178→
   179→    const events: CalendarEvent[] = [];
   180→
   181→    // Split into individual events
   182→    const eventBlocks = icsData.split('BEGIN:VEVENT').slice(1);
   183→
   184→    eventBlocks.forEach((block, index) => {
   185→      const endIndex = block.indexOf('END:VEVENT');
   186→      if (endIndex === -1) return;
   187→
   188→      const eventContent = block.slice(0, endIndex);
   189→      const lines = eventContent.split(/\r?\n/).filter(l => l.trim());
   190→
   191→      const event: Partial<CalendarEvent> = {
   192→        id: `imported-${Date.now()}-${index}`,
   193→      };
   194→
   195→      let startDate = '';
   196→      let endDate = '';
   197→      let startTime: string | undefined;
   198→      let endTime: string | undefined;
   199→
   200→      lines.forEach(line => {
   201→        // Handle folded lines (continuation)
   202→        const unfoldedLine = line.replace(/^\s+/, '');
   203→
   204→        if (unfoldedLine.startsWith('SUMMARY:')) {
   205→          event.title = unfoldedLine.slice(8);
   206→        } else if (unfoldedLine.startsWith('DESCRIPTION:')) {
   207→          event.description = unfoldedLine.slice(12).replace(/\\n/g, '\n').replace(/\\,/g, ',');
   208→        } else if (unfoldedLine.startsWith('LOCATION:')) {
   209→          event.location = unfoldedLine.slice(9);
   210→        } else if (unfoldedLine.startsWith('UID:')) {
   211→          // Use UID if available
   212→          event.id = unfoldedLine.slice(4);
   213→        } else if (unfoldedLine.startsWith('DTSTART')) {
   214→          const parsed = parseICSDateTime(unfoldedLine);
   215→          startDate = parsed.date;
   216→          startTime = parsed.time;
   217→        } else if (unfoldedLine.startsWith('DTEND')) {
   218→          const parsed = parseICSDateTime(unfoldedLine);
   219→          endDate = parsed.date;
