   167→  const setNavOrder = useSidebarNavStore((state) => state.setNavOrder);
   168→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   169→  const location = useLocation();
   170→  const [pageSettingsOpen, setPageSettingsOpen] = useState<string | null>(null);
   171→  const [justDragged, setJustDragged] = useState(false);
   172→
   173→  const isActive = (path: string) => location.pathname === path;
   174→
   175→  // Check if any child of a parent is active (for highlighting parent when child is active)
   176→  const isChildActive = (item: NavItem) => {
   177→    if (!item.children) return false;
   178→    return item.children.some((child) => location.pathname === child.path);
   179→  };
   180→
   181→  // Configure drag sensors (require 5px movement to start dragging)
   182→  const sensors = useSensors(
   183→    useSensor(PointerSensor, {
   184→      activationConstraint: {
   185→        distance: 5,
   186→      },
   187→    })
   188→  );
   189→
   190→  // Sort draggable navigation items by saved order
   191→  const sortedDraggableNavigation = [...draggableNavigation].sort((a, b) => {
   192→    const aIndex = navOrder.indexOf(a.path);
   193→    const bIndex = navOrder.indexOf(b.path);
   194→    // If path not found in order, put it at the end
   195→    return (aIndex === -1 ? 999 : aIndex) - (bIndex === -1 ? 999 : bIndex);
   196→  });
   197→
   198→  const handleDragEnd = (event: DragEndEvent) => {
   199→    const { active, over } = event;
   200→
   201→    setJustDragged(true);
   202→
   203→    if (over && active.id !== over.id) {
   204→      const oldIndex = navOrder.indexOf(active.id as string);
   205→      const newIndex = navOrder.indexOf(over.id as string);
   206→
   207→      if (oldIndex !== -1 && newIndex !== -1) {
   208→        const newOrder = arrayMove(navOrder, oldIndex, newIndex);
   209→        setNavOrder(newOrder);
   210→      }
   211→    }
   212→
   213→    // Reset justDragged flag after a short delay
   214→    setTimeout(() => setJustDragged(false), 100);
   215→  };
   216→
   217→  const handlePageSettings = (e: React.MouseEvent, path: string) => {
   218→    e.preventDefault();
   219→    e.stopPropagation();
   220→    setPageSettingsOpen(path);
   221→  };
   222→
   223→  // Close mobile menu on route change
   224→  useEffect(() => {
   225→    setMobileMenuOpen(false);
   226→  }, [location.pathname, setMobileMenuOpen]);
   227→
   228→  // Keyboard shortcut: Cmd/Ctrl + B to toggle
   229→  useEffect(() => {
   230→    const handleKeyDown = (e: KeyboardEvent) => {
   231→      if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
   232→        e.preventDefault();
   233→        toggleCollapse();
   234→      }
   235→    };
   236→
   237→    window.addEventListener('keydown', handleKeyDown);
   238→    return () => window.removeEventListener('keydown', handleKeyDown);
   239→  }, [toggleCollapse]);
   240→
   241→  return (
   242→    <>
   243→      {/* Mobile backdrop */}
   244→      {isMobileMenuOpen && (
   245→        <div
   246→          className="lg:hidden fixed inset-0 bg-black/50 z-30"
   247→          onClick={() => setMobileMenuOpen(false)}
   248→        />
   249→      )}
   250→
   251→      {/* Sidebar */}
   252→      <aside
   253→        aria-label="Main navigation sidebar"
   254→        className={`
   255→          fixed left-0 top-0 h-screen
   256→          bg-surface-light-elevated dark:bg-surface-dark
   257→          border-r border-border-light dark:border-border-dark
   258→          transition-all duration-200 ease-in-out
   259→          flex flex-col
   260→          z-40
   261→          ${isCollapsed ? 'w-[60px]' : 'w-[210px]'}
   262→
   263→          ${/* Mobile: slide in/out as drawer */ ''}
   264→          lg:translate-x-0
   265→          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
   266→        `}
   267→      >
   268→      {/* Logo Section */}
   269→      <div className="p-4 border-b border-border-light dark:border-border-dark">
   270→        <Link
   271→          to="/"
   272→          className="flex items-center gap-3 overflow-hidden"
   273→        >
   274→          <img
   275→            src="/images/logos/nb3.png"
   276→            alt="Neuman Brain"
   277→            className="w-8 h-8 flex-shrink-0 rounded-button"
   278→          />
   279→          {!isCollapsed && (
   280→            <div className="flex flex-col min-w-0">
   281→              <h1 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
   282→                NEUMAN BRAIN
   283→              </h1>
   284→              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary truncate">
   285→                Management Platform
   286→              </p>
   287→            </div>
   288→          )}
   289→        </Link>
   290→      </div>
   291→
   292→      {/* Navigation Items */}
   293→      <nav aria-label="Primary navigation" className="flex-1 overflow-y-auto py-4">
   294→        <ul className="space-y-1 px-2">
   295→          {/* Fixed Navigation Items (Dashboard - not draggable, supports children) */}
   296→          {fixedNavigation.map((item) => {
   297→            const hasChildren = item.children && item.children.length > 0;
   298→            const expanded = isExpanded(item.path);
   299→            const parentActive = isActive(item.path);
   300→            const childActive = isChildActive(item);
   301→
   302→            return (
   303→              <li key={item.path}>
   304→                {/* Parent Item */}
   305→                <div className="flex items-center">
   306→                  <Link
   307→                    to={item.path}
   308→                    className={`
   309→                      flex-1 flex items-center gap-3 px-3 h-10 rounded-button
   310→                      transition-all duration-standard ease-smooth
   311→                      relative group
   312→                      ${
   313→                        parentActive || childActive
   314→                          ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   315→                          : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   316→                      }
   317→                    `}
   318→                    title={isCollapsed ? item.label : undefined}
   319→                  >
   320→                    {/* Active indicator (left accent) */}
   321→                    {parentActive && (
   322→                      <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   323→                    )}
   324→
   325→                    {/* Icon - Fixed 20px size */}
   326→                    <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">
   327→                      {item.icon}
   328→                    </span>
   329→
   330→                    {/* Label (hidden when collapsed) */}
   331→                    {!isCollapsed && (
   332→                      <>
   333→                        <span className="flex-1 text-base leading-5 font-medium truncate">
   334→                          {item.label}
   335→                        </span>
   336→
   337→                        {/* Page Settings Icon (shown on hover) */}
   338→                        {item.hasSettings && (
   339→                          <button
   340→                            onClick={(e) => handlePageSettings(e, item.path)}
   341→                            className="
   342→                              opacity-0 group-hover:opacity-100
   343→                              w-5 h-5 flex items-center justify-center flex-shrink-0
   344→                              text-text-light-secondary dark:text-text-dark-secondary
   345→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   346→                              transition-opacity duration-200
   347→                            "
   348→                            title="Page Settings"
   349→                          >
   350→                            <span className="text-sm">⚙</span>
   351→                          </button>
   352→                        )}
   353→
   354→                        {/* Expand/Collapse Chevron (for items with children) */}
   355→                        {hasChildren && (
   356→                          <button
   357→                            onClick={(e) => {
   358→                              e.preventDefault();
   359→                              e.stopPropagation();
   360→                              toggleExpanded(item.path);
   361→                            }}
   362→                            className="
   363→                              w-5 h-5 flex items-center justify-center flex-shrink-0
   364→                              text-text-light-secondary dark:text-text-dark-secondary
   365→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   366→                              transition-transform duration-200
   367→                            "
   368→                            title={expanded ? 'Collapse' : 'Expand'}
   369→                          >
   370→                            <span
   371→                              className={`text-xs transition-transform duration-200 ${
   372→                                expanded ? 'rotate-90' : ''
   373→                              }`}
   374→                            >
   375→                              ▶
   376→                            </span>
   377→                          </button>
   378→                        )}
   379→                      </>
   380→                    )}
   381→
   382→                    {/* Tooltip for collapsed state */}
   383→                    {isCollapsed && (
   384→                      <div className="
   385→                        absolute left-full ml-2 px-2 py-1
   386→                        bg-surface-light-elevated dark:bg-surface-dark-elevated
   387→                        text-text-light-primary dark:text-text-dark-primary text-xs rounded
   388→                        opacity-0 group-hover:opacity-100
   389→                        pointer-events-none transition-opacity duration-200
   390→                        whitespace-nowrap z-50
   391→                      ">
   392→                        {item.label}
   393→                      </div>
   394→                    )}
   395→                  </Link>
   396→                </div>
   397→
   398→                {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   399→                {hasChildren && expanded && !isCollapsed && (
   400→                  <ul className="ml-6 mt-1 space-y-1">
   401→                    {item.children!.map((child) => (
