   283→          log.error('Output stream error', { error: err });
   284→        }
   285→      });
   286→
   287→      // Wait for exit
   288→      const exitCode = await process.exit;
   289→      this.currentProcess = null;
   290→
   291→      log.debug('Command completed', { command: command.name, exitCode });
   292→      return exitCode;
   293→    } catch (error) {
   294→      log.error('Command execution failed', { command: command.raw, error });
   295→      onStderr(`\x1b[31mError: ${error}\x1b[0m\n`);
   296→      this.currentProcess = null;
   297→      return 1;
   298→    }
   299→  }
   300→
   301→  async executeAI(
   302→    command: ShellCommand,
   303→    onOutput: (data: string) => void,
   304→  ): Promise<number> {
   305→    const prompt = command.args.join(' ');
   306→    log.info('AI command', { prompt: prompt.substring(0, 100) });
   307→
   308→    // Show thinking indicator
   309→    onOutput('\x1b[36m⏳ Thinking...\x1b[0m\n');
   310→
   311→    try {
   312→      const result = await processAICommand(prompt);
   313→
   314→      // Clear thinking indicator (move up and clear line)
   315→      onOutput('\x1b[1A\x1b[2K');
   316→
   317→      // Handle error
   318→      if (result.error) {
   319→        onOutput(`\x1b[31m${result.error}\x1b[0m\n`);
   320→        return 1;
   321→      }
   322→
   323→      // Show explanation if present
   324→      if (result.explanation) {
   325→        onOutput(`\x1b[90m${result.explanation}\x1b[0m\n`);
   326→      }
   327→
   328→      // Show commands
   329→      if (result.commands.length === 0) {
   330→        onOutput('\x1b[33mNo commands generated.\x1b[0m\n');
   331→        return 0;
   332→      }
   333→
   334→      // Display generated commands
   335→      onOutput('\x1b[32m📋 Generated commands:\x1b[0m\n');
   336→      for (const cmd of result.commands) {
   337→        onOutput(`  \x1b[36m$ ${cmd}\x1b[0m\n`);
   338→      }
   339→      onOutput('\n');
   340→
   341→      // Ask user to confirm (for now, just show them)
   342→      onOutput('\x1b[90mCopy and paste to execute,\x1b[0m\n');
   343→      onOutput('\x1b[90mor type the command manually.\x1b[0m\n');
   344→
   345→      return 0;
   346→    } catch (error) {
   347→      log.error('AI command execution failed', { error });
   348→      onOutput('\x1b[1A\x1b[2K'); // Clear thinking indicator
   349→      onOutput(`\x1b[31mAI Error: ${error}\x1b[0m\n`);
   350→      return 1;
   351→    }
   352→  }
   353→
   354→  kill() {
   355→    if (this.currentProcess) {
   356→      log.info('Killing current process');
   357→      this.currentProcess.kill();
   358→      this.currentProcess = null;
   359→    } else {
   360→      log.debug('Kill requested (no active process)');
   361→    }
   362→  }
   363→}
   364→
   365→export const shellExecutor = new ShellExecutor();
   366→
   367→// ==================== SHELL RUNNER ====================
   368→
   369→/**
   370→ * Main entry point for running commands
   371→ */
   372→export const runCommand = async (
   373→  input: string,
   374→  context: ShellContext,
   375→  onOutput: (data: string) => void,
   376→): Promise<number> => {
   377→  const command = parseCommand(input);
   378→
   379→  log.debug('Running command', { type: command.type, name: command.name });
   380→
   381→  switch (command.type) {
   382→    case 'builtin': {
   383→      const result = await shellExecutor.executeBuiltin(command, context);
   384→      if (result) {
   385→        onOutput(result + '\n');
   386→      }
   387→      return 0;
   388→    }
   389→
   390→    case 'ai': {
   391→      return shellExecutor.executeAI(command, onOutput);
   392→    }
   393→
   394→    case 'system': {
   395→      return shellExecutor.executeSystem(command, onOutput, onOutput);
   396→    }
   397→
   398→    default:
   399→      onOutput('\x1b[31mUnknown command type\x1b[0m\n');
   400→      return 1;
   401→  }
   402→};
   403→
   404→// ==================== UTILITIES ====================
   405→
   406→/**
   407→ * Create a shell context from store state
   408→ */
   409→export const createShellContext = (
   410→  terminal: ShellContext['terminal'],
   411→  store: {
   412→    activeProjectId: string | null;
   413→    commandHistory: { command: string; timestamp: string }[];
   414→    projects: Record<string, PhantomProject>;
   415→    createProject: (project: Omit<PhantomProject, 'id' | 'createdAt' | 'updatedAt'>) => string;
   416→  }
   417→): ShellContext => ({
   418→  terminal,
   419→  activeProjectId: store.activeProjectId,
   420→  getHistory: () => store.commandHistory,
   421→  getProjects: () => Object.values(store.projects).map(p => ({
   422→    id: p.id,
   423→    name: p.name,
   424→    metadata: p.metadata,
   425→  })),
   426→  createProject: (name: string) => store.createProject({
   427→    name,
   428→    files: {},
   429→    metadata: {},
   430→  }),
   431→});
