     1→/**
     2→ * WebContainer Service
     3→ *
     4→ * Manages WebContainer lifecycle:
     5→ * - Boot/teardown
     6→ * - File system operations
     7→ * - Process spawning
     8→ * - Dev server management
     9→ *
    10→ * WebContainer runs a full Node.js environment in the browser
    11→ * using WebAssembly. Requires Cross-Origin Isolation headers.
    12→ */
    13→
    14→import { WebContainer, type FileSystemTree } from '@webcontainer/api';
    15→import { logger } from '../logger';
    16→import { usePhantomShellStore } from '../../stores/usePhantomShellStore';
    17→
    18→const log = logger.module('PhantomShell:WebContainer');
    19→
    20→// Singleton instance
    21→let webcontainerInstance: WebContainer | null = null;
    22→let bootPromise: Promise<WebContainer> | null = null;
    23→
    24→// ==================== BOOT ====================
    25→
    26→/**
    27→ * Boot WebContainer instance (singleton)
    28→ *
    29→ * This is an expensive operation (~2-5 seconds) so we:
    30→ * 1. Only boot once per session
    31→ * 2. Reuse the same instance
    32→ * 3. Show loading state to user
    33→ */
    34→export const bootWebContainer = async (): Promise<WebContainer> => {
    35→  // Return existing instance
    36→  if (webcontainerInstance) {
    37→    log.debug('Returning existing WebContainer instance');
    38→    return webcontainerInstance;
    39→  }
    40→
    41→  // Return pending boot
    42→  if (bootPromise) {
    43→    log.debug('Waiting for pending WebContainer boot');
    44→    return bootPromise;
    45→  }
    46→
    47→  // Check for Cross-Origin Isolation
    48→  if (typeof crossOriginIsolated !== 'undefined' && !crossOriginIsolated) {
    49→    const error = 'WebContainer requires Cross-Origin Isolation. ' +
    50→      'Ensure COEP and COOP headers are set in vite.config.ts and public/_headers';
    51→    log.error(error);
    52→    usePhantomShellStore.getState().setWebContainerError(error);
    53→    throw new Error(error);
    54→  }
    55→
    56→  // Start boot process
    57→  log.info('Booting WebContainer...');
    58→  usePhantomShellStore.getState().setWebContainerBooting(true);
    59→
    60→  bootPromise = WebContainer.boot()
    61→    .then((instance) => {
    62→      webcontainerInstance = instance;
    63→      usePhantomShellStore.getState().setWebContainerReady(true);
    64→      usePhantomShellStore.getState().setWebContainerBooting(false);
    65→
    66→      log.info('WebContainer booted successfully');
    67→
    68→      // Set up server-ready listener for dev servers
    69→      instance.on('server-ready', (port, url) => {
    70→        log.info('Dev server ready', { port, url });
    71→        usePhantomShellStore.getState().setDevServer(url, port);
    72→        usePhantomShellStore.getState().setDevServerRunning(true);
    73→      });
    74→
    75→      return instance;
    76→    })
    77→    .catch((error) => {
    78→      log.error('WebContainer boot failed', { error });
    79→      usePhantomShellStore.getState().setWebContainerError(String(error));
    80→      usePhantomShellStore.getState().setWebContainerBooting(false);
    81→      bootPromise = null;
    82→      throw error;
    83→    });
    84→
    85→  return bootPromise;
    86→};
    87→
    88→/**
    89→ * Get WebContainer instance (must be booted first)
    90→ */
    91→export const getWebContainer = (): WebContainer | null => {
    92→  return webcontainerInstance;
    93→};
    94→
    95→// ==================== FILE SYSTEM ====================
    96→
    97→/**
    98→ * Mount a file system tree to WebContainer
    99→ */
   100→export const mountFileSystem = async (
   101→  files: FileSystemTree,
   102→  path: string = '/'
   103→): Promise<void> => {
   104→  const container = await bootWebContainer();
   105→  log.debug('Mounting file system', { path, fileCount: Object.keys(files).length });
   106→  await container.mount(files, { mountPoint: path });
   107→  log.info('File system mounted', { path });
   108→};
   109→
   110→/**
   111→ * Read a file from WebContainer
   112→ */
   113→export const readFile = async (path: string): Promise<string> => {
   114→  const container = await bootWebContainer();
   115→  return container.fs.readFile(path, 'utf-8');
   116→};
   117→
   118→/**
   119→ * Write a file to WebContainer
   120→ */
   121→export const writeFile = async (path: string, contents: string): Promise<void> => {
   122→  const container = await bootWebContainer();
   123→  await container.fs.writeFile(path, contents);
   124→  log.debug('File written', { path, size: contents.length });
   125→};
   126→
   127→/**
   128→ * Create directory in WebContainer
   129→ */
   130→export const mkdir = async (path: string, recursive = true): Promise<void> => {
   131→  const container = await bootWebContainer();
   132→  if (recursive) {
   133→    await container.fs.mkdir(path, { recursive: true });
   134→  } else {
   135→    await container.fs.mkdir(path);
   136→  }
   137→  log.debug('Directory created', { path });
   138→};
   139→
   140→/**
   141→ * List directory contents
   142→ */
   143→export const readdir = async (path: string): Promise<string[]> => {
