   147→
   148→/**
   149→ * Remove file or directory
   150→ */
   151→export const rm = async (path: string, recursive: boolean = false): Promise<void> => {
   152→  const container = await bootWebContainer();
   153→  await container.fs.rm(path, { recursive });
