   194→            vite: '^5.0.0',
   195→          },
   196→        }, null, 2),
   197→      },
   198→    },
   199→    'vite.config.js': {
   200→      file: {
   201→        contents: `import { defineConfig } from 'vite'
   202→import react from '@vitejs/plugin-react'
   203→
   204→export default defineConfig({
   205→  plugins: [react()],
   206→})`,
   207→      },
   208→    },
   209→    'index.html': {
   210→      file: {
   211→        contents: `<!DOCTYPE html>
   212→<html lang="en">
   213→<head>
   214→  <meta charset="UTF-8" />
   215→  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
   216→  <title>Phantom Project</title>
