   291→  // Deep clone to avoid mutating the template
   292→  const filesCopy = JSON.parse(JSON.stringify(files)) as FileSystemTree;
   293→
   294→  // Update package.json with project name
   295→  const pkgJson = filesCopy['package.json'];
   296→  if (pkgJson && 'file' in pkgJson && 'contents' in pkgJson.file) {
   297→    const contents = pkgJson.file.contents;
   298→    if (typeof contents === 'string') {
   299→      const pkg = JSON.parse(contents);
