   320→    store.setWebContainerReady(false);
   321→    store.setDevServer(null, null);
   322→    store.setDevServerRunning(false);
   323→
   324→    log.info('WebContainer references cleared');
   325→  }
   326→};
   327→
   328→// ==================== UTILITIES ====================
   329→
   330→/**
   331→ * Check if WebContainer is supported and enabled
   332→ */
   333→export const isWebContainerSupported = (): {
   334→  supported: boolean;
   335→  reason?: string;
   336→} => {
   337→  if (typeof SharedArrayBuffer === 'undefined') {
   338→    return {
   339→      supported: false,
   340→      reason: 'SharedArrayBuffer not available (requires Cross-Origin Isolation)',
   341→    };
   342→  }
   343→
   344→  if (typeof crossOriginIsolated !== 'undefined' && !crossOriginIsolated) {
   345→    return {
   346→      supported: false,
   347→      reason: 'Cross-Origin Isolation not enabled (COEP/COOP headers required)',
   348→    };
   349→  }
   350→
   351→  return { supported: true };
   352→};
