import { useState } from 'react';
import { List, BarChart3, FolderOpen, Calendar } from 'lucide-react';
import { TimeEntryList } from '../components/TimeEntryList';
import { TimeEntrySummary } from '../components/TimeEntrySummary';
import { EditTimeEntryModal } from '../components/EditTimeEntryModal';
import { EventCreateModal } from '../components/EventCreateModal';
import { ProjectManager } from '../components/ProjectManager';
import { TimeEntryCalendar } from '../components/TimeEntryCalendar';
import { PageHeader } from '../components/PageHeader';
import type { TimeEntry, CalendarEvent } from '../types';

type TabType = 'entries' | 'summary' | 'calendar' | 'projects';

/**
 * TimeTracking Page (Now with Event Planning!)
 * UNIFIED: Time tracking + Event planning in one beautiful interface
 */
export function TimeTracking() {
  const [activeTab, setActiveTab] = useState<TabType>('calendar');
  const [editingEntry, setEditingEntry] = useState<TimeEntry | null>(null);
  const [eventModalData, setEventModalData] = useState<{ dateKey: string; event?: CalendarEvent } | null>(null);

  return (
    <div className="schedule-page">
      {/* Page Header */}
      <PageHeader />

      {/* Tab Navigation */}
      <div className="mb-6 border-b border-border-light dark:border-border-dark">
        <div className="flex gap-1">
          <button
            onClick={() => setActiveTab('entries')}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
              activeTab === 'entries'
                ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            <List className="w-4 h-4" />
            Entries
          </button>
          <button
            onClick={() => setActiveTab('summary')}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
              activeTab === 'summary'
                ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            <BarChart3 className="w-4 h-4" />
            Summary
          </button>
          <button
            onClick={() => setActiveTab('calendar')}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
              activeTab === 'calendar'
                ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            <Calendar className="w-4 h-4" />
            Calendar
          </button>
          <button
            onClick={() => setActiveTab('projects')}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
              activeTab === 'projects'
                ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            <FolderOpen className="w-4 h-4" />
            Projects
          </button>
        </div>
      </div>

      {/* Tab Content */}
      <div className="min-h-[600px]">
        {activeTab === 'entries' && (
          <TimeEntryList onEditEntry={(entry) => setEditingEntry(entry)} />
        )}
        {activeTab === 'summary' && <TimeEntrySummary />}
        {activeTab === 'calendar' && (
          <TimeEntryCalendar
            onEditEntry={(entry) => setEditingEntry(entry)}
            onCreateEvent={(dateKey) => setEventModalData({ dateKey })}
            onEditEvent={(event, dateKey) => setEventModalData({ dateKey, event })}
          />
        )}
        {activeTab === 'projects' && <ProjectManager />}
      </div>

      {/* Edit Time Entry Modal */}
      {editingEntry && (
        <EditTimeEntryModal
          entry={editingEntry}
          onClose={() => setEditingEntry(null)}
        />
      )}

      {/* Create/Edit Event Modal */}
      {eventModalData && (
        <EventCreateModal
          dateKey={eventModalData.dateKey}
          event={eventModalData.event}
          onClose={() => setEventModalData(null)}
        />
      )}
    </div>
  );
}

/**
 * Dashboard Widget Registry
 *
 * Central registry of all available widgets with metadata, API configuration,
 * and lazy-loaded component references.
 *
 * Adding a new widget:
 * 1. Create the widget component in src/widgets/Dashboard/
 * 2. Add an entry to WIDGET_REGISTRY below
 * 3. That's it! The widget will be available in the Widget Manager
 */

import { lazy, type LazyExoticComponent, type FC } from 'react';

export type WidgetCategory = 'core' | 'productivity' | 'news' | 'fun' | 'finance' | 'visual' | 'dev' | 'utility';

// Props interface for widget components
export interface WidgetComponentProps {
  widgetId?: string;
}

export interface WidgetDefinition {
  id: string;
  name: string;
  description: string;
  icon: string; // Emoji icon
  category: WidgetCategory;
  apiUrl?: string;
  apiKey?: string; // 'DEMO_KEY' for APIs that need keys but offer demo access
  requiresAuth?: boolean; // If user needs to provide API key/username
  defaultEnabled: boolean;
  // Lazy-loaded component (automatically generated from id)
  component?: LazyExoticComponent<FC<WidgetComponentProps>>;
}

/**
 * Maps widget ID to its file name in the Dashboard folder
 * Uses convention: widget ID -> PascalCase + "Widget"
 * e.g., "hackernews" -> "HackerNewsWidget"
 */
const WIDGET_FILE_NAMES: Record<string, string> = {
  taskssummary: 'TasksSummaryWidget',
  tasksquickadd: 'TasksQuickAddWidget',
  upcomingevents: 'UpcomingEventsWidget',
  recentnotes: 'RecentNotesWidget',
  quote: 'QuoteWidget',
  crypto: 'CryptoWidget',
  hackernews: 'HackerNewsWidget',
  facts: 'FactsWidget',
  github: 'GitHubWidget',
  joke: 'JokeWidget',
  unsplash: 'UnsplashWidget',
  pomodoro: 'PomodoroWidget',
  reddit: 'RedditWidget',
  devto: 'DevToWidget',
  wordofday: 'WordOfDayWidget',
  currency: 'CurrencyWidget',
  worldclock: 'WorldClockWidget',
  ipinfo: 'IPInfoWidget',
  qrcode: 'QRCodeWidget',
  colorpalette: 'ColorPaletteWidget',
  weathermap: 'WeatherMapWidget',
  calculator: 'CalculatorWidget',
  unitconverter: 'UnitConverterWidget',
  countdown: 'CountdownWidget',
